import os
import pickle

cache_file = 'cache.p'


class Memoizer:
    def __init__(self, func):
        self.cache = {}
        self.func = func

    def __call__(self, *args):
        if args in self.cache:
            return self.cache[args]

        val = self.func(*args)

        self.cache[args] = val

        self.save()
        return val

    def save(self):
        f = open(cache_file, 'wb')
        pickle.dump(self.cache, f)
        os.chmod(cache_file, 0o777)


@Memoizer
def fib(n):
    if n <= 1:
        return n

    return fib(n-1) + fib(n-2)
